'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { Heart, BookOpen, Star, MessageCircle, Lightbulb, Quote, FileText, Link as LinkIcon } from 'lucide-react';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';
import type { ContentItem } from '@/types';

interface ContentCardProps {
  item: ContentItem;
  onToggleFavorite?: (id: string) => void;
}

const typeConfig: Record<
  ContentItem['type'],
  { label: string; icon: React.ElementType; color: string; badgeVariant: 'green' | 'gold' | 'teal' | 'blue' | 'red' | 'default' }
> = {
  verse: { label: 'Verset', icon: BookOpen, color: '#3aaa60', badgeVariant: 'green' },
  hadith: { label: 'Hadith', icon: Star, color: '#d4991a', badgeVariant: 'gold' },
  explanation: { label: 'Explication', icon: Lightbulb, color: '#24ad9d', badgeVariant: 'teal' },
  reminder: { label: 'Rappel', icon: MessageCircle, color: '#6366f1', badgeVariant: 'blue' },
  quote: { label: 'Citation', icon: Quote, color: '#ec4899', badgeVariant: 'red' },
  note: { label: 'Note', icon: FileText, color: '#a8b4c2', badgeVariant: 'default' },
  proof: { label: 'Preuve', icon: FileText, color: '#8b5cf6', badgeVariant: 'blue' },
  link: { label: 'Lien', icon: LinkIcon, color: '#3ec8b6', badgeVariant: 'teal' },
};

const ContentCard: React.FC<ContentCardProps> = ({ item, onToggleFavorite }) => {
  const config = typeConfig[item.type];
  const Icon = config.icon;

  return (
    <Card hoverable glowColor="none" className="overflow-hidden">
      <div className="p-4 sm:p-5">
        {/* Header: type badge + favorite */}
        <div className="flex items-start justify-between gap-3 mb-3">
          <Badge variant={config.badgeVariant} size="sm">
            <Icon size={12} className="mr-1.5" />
            {config.label}
          </Badge>

          <motion.button
            whileTap={{ scale: 0.8 }}
            onClick={() => onToggleFavorite?.(item.id)}
            className="shrink-0 p-1.5 rounded-lg transition-colors cursor-pointer"
            style={{ background: item.isFavorite ? 'rgba(236, 72, 153, 0.15)' : 'transparent' }}
            aria-label={item.isFavorite ? 'Retirer des favoris' : 'Ajouter aux favoris'}
          >
            <Heart
              size={18}
              fill={item.isFavorite ? '#ec4899' : 'none'}
              style={{ color: item.isFavorite ? '#ec4899' : 'var(--text-muted)' }}
            />
          </motion.button>
        </div>

        {/* Title */}
        {item.title && (
          <h3
            className="text-sm font-semibold mb-2 leading-snug"
            style={{ color: 'var(--text-primary)' }}
          >
            {item.title}
          </h3>
        )}

        {/* Arabic text */}
        {item.contentAr && (
          <p
            className="text-lg leading-loose mb-3 text-right font-serif"
            style={{ color: config.color, direction: 'rtl' }}
          >
            {item.contentAr}
          </p>
        )}

        {/* Content */}
        <p
          className="text-sm leading-relaxed mb-3"
          style={{ color: 'var(--text-secondary)' }}
        >
          {item.content}
        </p>

        {/* Source & Reference */}
        {(item.source || item.reference) && (
          <p
            className="text-xs mb-3 italic"
            style={{ color: 'var(--text-muted)' }}
          >
            {item.source}
            {item.source && item.reference && ' — '}
            {item.reference}
          </p>
        )}

        {/* Tags */}
        {item.tags.length > 0 && (
          <div className="flex flex-wrap gap-1.5">
            {item.tags.map((tag) => (
              <span
                key={tag}
                className="px-2 py-0.5 text-xs rounded-full"
                style={{
                  background: 'rgba(255, 255, 255, 0.06)',
                  color: 'var(--text-muted)',
                }}
              >
                {tag}
              </span>
            ))}
          </div>
        )}
      </div>
    </Card>
  );
};

export default ContentCard;
