'use client';

import React, { useState, useMemo } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { motion } from 'framer-motion';
import {
  Share2,
  BookOpen,
  FolderOpen,
} from 'lucide-react';
import { themes } from '@/data/themes';
import { contentItems } from '@/data/content';
import PageHeader from '@/components/layout/PageHeader';
import Tabs from '@/components/ui/Tabs';
import Badge from '@/components/ui/Badge';
import Card from '@/components/ui/Card';
import EmptyState from '@/components/ui/EmptyState';
import SectionHeader from '@/components/ui/SectionHeader';
import ContentCard from '@/components/themes/ContentCard';
import type { ContentItem } from '@/types';

const contentTabs = [
  { id: 'all', label: 'Tous' },
  { id: 'verse', label: 'Versets' },
  { id: 'hadith', label: 'Hadiths' },
  { id: 'explanation', label: 'Explications' },
  { id: 'reminder', label: 'Rappels' },
  { id: 'quote', label: 'Citations' },
];

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.08 },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 16 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4, ease: 'easeOut' } },
};

export default function ThemeDetailPage() {
  const params = useParams<{ id: string }>();
  const [activeTab, setActiveTab] = useState('all');
  const [favorites, setFavorites] = useState<Set<string>>(() => {
    const favs = new Set<string>();
    contentItems.forEach((item) => {
      if (item.isFavorite) favs.add(item.id);
    });
    return favs;
  });

  const theme = themes.find((t) => t.id === params.id);

  const themeContent = useMemo(() => {
    if (!theme) return [];
    return contentItems.filter((c) => c.themeId === theme.id);
  }, [theme]);

  const filteredContent = useMemo(() => {
    if (activeTab === 'all') return themeContent;
    return themeContent.filter((c) => c.type === activeTab);
  }, [themeContent, activeTab]);

  const relatedThemes = useMemo(() => {
    if (!theme) return [];
    return themes
      .filter(
        (t) =>
          t.id !== theme.id &&
          t.tags.some((tag) => theme.tags.includes(tag))
      )
      .slice(0, 3);
  }, [theme]);

  const toggleFavorite = (id: string) => {
    setFavorites((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const handleShare = async () => {
    if (typeof navigator !== 'undefined' && navigator.share && theme) {
      try {
        await navigator.share({
          title: theme.title,
          text: theme.description,
          url: window.location.href,
        });
      } catch {
        // User cancelled or share not supported
      }
    }
  };

  // Not found state
  if (!theme) {
    return (
      <div className="pb-nav py-4 sm:py-6">
        <PageHeader title="Thème introuvable" backButton />
        <EmptyState
          icon={FolderOpen}
          title="Thème introuvable"
          description="Le thème que vous recherchez n'existe pas ou a été supprimé."
          actionLabel="Retour à l'exploration"
          onAction={() => window.location.assign('/explore')}
        />
      </div>
    );
  }

  // Build items with current favorite state
  const displayItems: ContentItem[] = filteredContent.map((item) => ({
    ...item,
    isFavorite: favorites.has(item.id),
  }));

  return (
    <div className="pb-nav space-y-6 py-4 sm:py-6">
      <PageHeader
        title={theme.title}
        backButton
        rightAction={
          <button
            onClick={handleShare}
            className="flex h-9 w-9 items-center justify-center rounded-xl transition-colors cursor-pointer"
            style={{ background: 'rgba(255,255,255,0.06)' }}
            aria-label="Partager"
          >
            <Share2 size={18} style={{ color: 'var(--text-secondary)' }} />
          </button>
        }
      />

      {/* Hero section */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <Card hoverable={false} className="overflow-hidden">
          <div
            className="p-5 sm:p-6"
            style={{ borderTop: `3px solid ${theme.color}` }}
          >
            <div className="flex items-start gap-4 mb-4">
              <div
                className="flex h-14 w-14 shrink-0 items-center justify-center rounded-2xl text-xl font-bold"
                style={{
                  background: `${theme.color}20`,
                  color: theme.color,
                }}
              >
                {theme.title.charAt(0)}
              </div>
              <div className="min-w-0 flex-1">
                <h2
                  className="text-xl font-bold leading-tight"
                  style={{ color: 'var(--text-primary)' }}
                >
                  {theme.title}
                </h2>
                {theme.titleAr && (
                  <p
                    className="text-base mt-1 font-serif"
                    style={{ color: theme.color, direction: 'rtl' }}
                  >
                    {theme.titleAr}
                  </p>
                )}
              </div>
            </div>

            <p
              className="text-sm leading-relaxed mb-4"
              style={{ color: 'var(--text-secondary)' }}
            >
              {theme.description}
            </p>

            {/* Meta info */}
            <div className="flex flex-wrap items-center gap-2 mb-4">
              <Badge variant="green" size="sm">
                <BookOpen size={12} className="mr-1" />
                {themeContent.length} contenu{themeContent.length !== 1 ? 's' : ''}
              </Badge>
              {typeof theme.progress === 'number' && (
                <Badge variant="gold" size="sm">{theme.progress}% complété</Badge>
              )}
            </div>

            {/* Progress bar */}
            {typeof theme.progress === 'number' && (
              <div
                className="h-2 w-full rounded-full overflow-hidden"
                style={{ background: 'rgba(255,255,255,0.08)' }}
              >
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${theme.progress}%` }}
                  transition={{ duration: 1, ease: 'easeOut' }}
                  className="h-full rounded-full"
                  style={{ background: theme.color }}
                />
              </div>
            )}

            {/* Tags */}
            {theme.tags.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mt-4">
                {theme.tags.map((tag) => (
                  <span
                    key={tag}
                    className="px-2.5 py-1 text-xs rounded-full"
                    style={{
                      background: 'rgba(255, 255, 255, 0.06)',
                      color: 'var(--text-muted)',
                    }}
                  >
                    #{tag}
                  </span>
                ))}
              </div>
            )}
          </div>
        </Card>
      </motion.div>

      {/* Content filter tabs */}
      <div className="overflow-x-auto no-scrollbar">
        <Tabs
          tabs={contentTabs}
          activeTab={activeTab}
          onChange={setActiveTab}
          className="w-max"
        />
      </div>

      {/* Content list */}
      {displayItems.length === 0 ? (
        <EmptyState
          icon={BookOpen}
          title="Aucun contenu"
          description={
            activeTab === 'all'
              ? 'Ce thème ne contient pas encore de contenu.'
              : 'Aucun contenu de ce type pour ce thème.'
          }
          actionLabel={activeTab !== 'all' ? 'Voir tout' : undefined}
          onAction={activeTab !== 'all' ? () => setActiveTab('all') : undefined}
        />
      ) : (
        <motion.div
          key={activeTab}
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="space-y-4"
        >
          {displayItems.map((item) => (
            <motion.div key={item.id} variants={itemVariants}>
              <ContentCard
                item={item}
                onToggleFavorite={toggleFavorite}
              />
            </motion.div>
          ))}
        </motion.div>
      )}

      {/* Related themes */}
      {relatedThemes.length > 0 && (
        <div className="space-y-4 pt-4">
          <SectionHeader
            title="Thèmes liés"
            subtitle="Continuez votre exploration"
          />

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {relatedThemes.map((related) => (
              <Link
                key={related.id}
                href={`/explore/${related.id}`}
                className="block"
              >
                <Card hoverable glowColor="green">
                  <div
                    className="p-4 flex items-center gap-3"
                    style={{ borderLeft: `3px solid ${related.color}` }}
                  >
                    <div
                      className="flex h-9 w-9 shrink-0 items-center justify-center rounded-xl text-sm font-bold"
                      style={{
                        background: `${related.color}20`,
                        color: related.color,
                      }}
                    >
                      {related.title.charAt(0)}
                    </div>
                    <div className="min-w-0">
                      <h4
                        className="text-sm font-semibold truncate"
                        style={{ color: 'var(--text-primary)' }}
                      >
                        {related.title}
                      </h4>
                      <p
                        className="text-xs truncate"
                        style={{ color: 'var(--text-muted)' }}
                      >
                        {related.contentCount} contenus
                      </p>
                    </div>
                  </div>
                </Card>
              </Link>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
